config {
  type: "incremental",
  uniqueKey: ["claim_id"],
  name: "incremental_warranty_claims",
  description: "Processes new warranty claims daily based on claim_date."
}

-- Pre-operation: Validate data quality (abort if negative repair costs are found)
pre_operations {
  ASSERT(
    (SELECT count(*) FROM ${ref("warranty_claims")} WHERE repair_cost < 0) = 0
  )
}

-- Main logic: Select only records that are new since the last run
SELECT
  claim_id,
  model,
  dealer,
  mileage,
  repair_cost,
  failure_code,
  claim_date
FROM ${ref("warranty_claims")}
${when(incremental(), 
  `WHERE claim_date > (SELECT MAX(claim_date) FROM ${self()})`
)}

-- Post-operation: Log the success of the incremental load
post_operations {
  -- In a production environment, this could be a call to a logging table
  -- or a simple dummy operation to verify the table state
  SELECT 1 as validation_complete
}

