document.getElementById('regionSelect').addEventListener('change', function() {
    const selectedRegion = this.value;
    const table = document.getElementById('myTable');
    const rows = table.getElementsByTagName('tr');

    // Start from index 1 to skip the table header
    for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        // Assuming region is in the second column (index 1)
        const regionCell = row.getElementsByTagName('td')[1];

        if (regionCell) {
            const regionText = regionCell.textContent || regionCell.innerText;

            // Show row if "All" is selected or if text matches
            if (selectedRegion === "All" || regionText === selectedRegion) {
                row.style.display = "";
            } else {
                row.style.display = "none";
            }
        }
    }
});

import React, { useState, useMemo } from 'react';

const WarrantyClaimsTable = ({ claims }) => {
  const [filterStatus, setFilterStatus] = useState('All');
  const [sortConfig, setSortConfig] = useState({ key: 'date', direction: 'desc' });

  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const filteredAndSortedClaims = useMemo(() => {
    let processedClaims = [...claims];

    // Filtering
    if (filterStatus !== 'All') {
      processedClaims = processedClaims.filter(c => c.status === filterStatus);
    }

    // Sorting
    processedClaims.sort((a, b) => {
      if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === 'asc' ? -1 : 1;
      if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });

    return processedClaims;
  }, [claims, filterStatus, sortConfig]);

  return (
    <div>
      <select onChange={(e) => setFilterStatus(e.target.value)}>
        <option value="All">All Statuses</option>
        <option value="Pending">Pending</option>
        <option value="Approved">Approved</option>
        <option value="Rejected">Rejected</option>
      </select>

      <table>
        <thead>
          <tr>
            <th onClick={() => handleSort('id')}>ID</th>
            <th onClick={() => handleSort('customer')}>Customer</th>
            <th onClick={() => handleSort('status')}>Status</th>
            <th onClick={() => handleSort('date')}>Date</th>
          </tr>
        </thead>
        <tbody>
          {filteredAndSortedClaims.map(claim => (
            <tr key={claim.id}>
              <td>{claim.id}</td>
              <td>{claim.customer}</td>
              <td>{claim.status}</td>
              <td>{claim.date}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default WarrantyClaimsTable;

import React, { useEffect, useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend } from 'recharts';

const WarrantyDashboard = () => {
  const [data, setData] = useState([]);
  const [filter, setFilter] = useState('All');

  useEffect(() => {
    fetch('http://localhost:5000/api/warranties')
      .then(res => res.json())
      .then(data => setData(data));
  }, []);

  const filteredData = filter === 'All' ? data : data.filter(d => d.status === filter);

  const chartData = [
    { name: 'Active', value: data.filter(d => d.status === 'Active').length },
    { name: 'Expired', value: data.filter(d => d.status === 'Expired').length },
    { name: 'Expiring Soon', value: data.filter(d => d.status === 'Expiring Soon').length },
  ];

  return (
    <div className="p-6">
      <h2>Warranty Dashboard</h2>
      <select onChange={(e) => setFilter(e.target.value)}>
        <option value="All">All</option>
        <option value="Active">Active</option>
        <option value="Expired">Expired</option>
      </select>

      <div style={{ height: 300 }}>
        <ResponsiveContainer>
          <PieChart>
            <Pie data={chartData} dataKey="value" nameKey="name" fill="#8884d8" />
            <Legend />
          </PieChart>
        </ResponsiveContainer>
      </div>

      <ul>
        {filteredData.map(item => (
          <li key={item.id}>{item.product} - {item.status} (Expires: {item.expiry})</li>
        ))}
      </ul>
    </div>
  );
};
export default WarrantyDashboard;

