import unittest

def add(a, b):
    return a + b

class TestAddFunction(unittest.TestCase):
    def test_positive_integers(self):
        self.assertEqual(add(1, 2), 3)

    def test_negative_integers(self):
        self.assertEqual(add(-1, -1), -2)
        self.assertEqual(add(-1, 1), 0)

    def test_zero(self):
        self.assertEqual(add(0, 0), 0)
        self.assertEqual(add(5, 0), 5)

    def test_floats(self):
        self.assertAlmostEqual(add(1.1, 2.2), 3.3, places=7)

    def test_strings(self):
        # Testing behavior with types that support '+'
        self.assertEqual(add("hello ", "world"), "hello world")

    def test_lists(self):
        self.assertEqual(add([1], [2]), [1, 2])

if __name__ == '__main__':
    unittest.main()

import numpy as np

class StandardScaler:
    def fit(self, X):
        self.mean = np.mean(X, axis=0)
        self.std = np.std(X, axis=0)
        return self

    def transform(self, X):
        return (X - self.mean) / self.std

class LinearRegression:
    def fit(self, X, y):
        # Adding bias term (column of 1s)
        X_b = np.c_[np.ones((X.shape[0], 1)), X]
        # Normal Equation: theta = (X^T * X)^-1 * X^T * y
        self.theta = np.linalg.inv(X_b.T.dot(X_b)).dot(X_b.T).dot(y)
        return self

    def predict(self, X):
        X_b = np.c_[np.ones((X.shape[0], 1)), X]
        return X_b.dot(self.theta)

class Pipeline:
    def __init__(self, steps):
        self.steps = steps # List of (name, object) tuples

    def fit(self, X, y):
        current_data = X
        for name, step in self.steps[:-1]:
            current_data = step.fit(current_data).transform(current_data)
        self.steps[-1][1].fit(current_data, y)
        return self

    def predict(self, X):
        current_data = X
        for name, step in self.steps[:-1]:
            current_data = step.transform(current_data)
        return self.steps[-1][1].predict(current_data)

